"use client";

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Play, Pause, Trash2, RotateCcw } from 'lucide-react';

interface AudioRecorderProps {
  onRecordingComplete: (blob: Blob | null) => void;
  initialBlob?: Blob | null;
}

export function AudioRecorder({ onRecordingComplete, initialBlob }: AudioRecorderProps) {
  const [isRecording, setIsRecording] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [audioBlob, setAudioBlob] = useState<Blob | null>(initialBlob || null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [duration, setDuration] = useState(0);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (initialBlob) {
      setAudioBlob(initialBlob);
      setAudioUrl(URL.createObjectURL(initialBlob));
    }
  }, [initialBlob]);

  useEffect(() => {
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
      if (audioUrl) URL.revokeObjectURL(audioUrl);
    };
  }, [audioUrl]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        setAudioBlob(blob);
        const url = URL.createObjectURL(blob);
        setAudioUrl(url);
        onRecordingComplete(blob);

        // Stop all tracks
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start(1000); // chunk every second just in case
      setIsRecording(true);
      setIsPaused(false);

      timerRef.current = setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);

    } catch (err) {
      console.error("Error accessing microphone", err);
      alert("Microphone access denied or not available.");
    }
  };

  const pauseRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.pause();
      setIsPaused(true);
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const resumeRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'paused') {
      mediaRecorderRef.current.resume();
      setIsPaused(false);
      timerRef.current = setInterval(() => {
        setDuration(prev => prev + 1);
      }, 1000);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setIsPaused(false);
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const deleteRecording = () => {
    setAudioBlob(null);
    if (audioUrl) URL.revokeObjectURL(audioUrl);
    setAudioUrl(null);
    setDuration(0);
    onRecordingComplete(null);
  };

  const formatTime = (secs: number) => {
    const m = Math.floor(secs / 60).toString().padStart(2, '0');
    const s = (secs % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  };

  if (audioUrl) {
    return (
      <div className="flex flex-col gap-2 p-3 border rounded-lg bg-gray-50 border-gray-200">
        <div className="flex items-center justify-between">
          <span className="text-sm font-medium text-gray-700">Audio Recorded</span>
          <button 
            type="button" 
            onClick={deleteRecording}
            className="text-red-500 hover:text-red-700 p-1"
          >
            <Trash2 size={16} />
          </button>
        </div>
        <audio src={audioUrl} controls className="w-full h-8" />
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-2 p-3 border rounded-lg bg-gray-50 border-gray-200">
      <div className="flex items-center justify-between">
        <span className="text-sm font-medium text-gray-700">
          {isRecording ? (isPaused ? "Paused" : "Recording...") : "Record Audio Note"}
        </span>
        {isRecording && (
          <span className={`text-sm font-mono ${!isPaused ? 'text-red-500 animate-pulse' : 'text-gray-500'}`}>
            {formatTime(duration)}
          </span>
        )}
      </div>

      <div className="flex gap-2">
        {!isRecording ? (
          <button
            type="button"
            onClick={startRecording}
            className="flex items-center gap-2 px-3 py-2 bg-red-100 text-red-600 rounded-md hover:bg-red-200 transition text-sm"
          >
            <Mic size={16} /> Start Recording
          </button>
        ) : (
          <>
            {isPaused ? (
              <button
                type="button"
                onClick={resumeRecording}
                className="flex items-center gap-2 px-3 py-2 bg-green-100 text-green-700 rounded-md hover:bg-green-200 transition text-sm flex-1 justify-center"
              >
                <Play size={16} /> Resume
              </button>
            ) : (
              <button
                type="button"
                onClick={pauseRecording}
                className="flex items-center gap-2 px-3 py-2 bg-yellow-100 text-yellow-700 rounded-md hover:bg-yellow-200 transition text-sm flex-1 justify-center"
              >
                <Pause size={16} /> Pause
              </button>
            )}

            <button
              type="button"
              onClick={stopRecording}
              className="flex items-center gap-2 px-3 py-2 bg-gray-800 text-white rounded-md hover:bg-gray-900 transition text-sm flex-1 justify-center"
            >
              <Square size={16} /> Stop
            </button>
          </>
        )}
      </div>
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { Listening } from '@/lib/firestore';
import { Bookmark, Youtube, PlayCircle, Loader2 } from 'lucide-react';
import { doc, getDoc, setDoc, deleteDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { useAuth } from '@/lib/auth-context';
import { SubmitPanel } from './SubmitPanel';

interface DailySadhanaCardProps {
  listening: Listening | null;
  publishedDateStr: string;
  isToday: boolean;
  onSubmitted?: () => void;
  alreadySubmitted?: boolean;
}

export function DailySadhanaCard({ 
  listening, 
  publishedDateStr, 
  isToday, 
  onSubmitted, 
  alreadySubmitted 
}: DailySadhanaCardProps) {
  const { user } = useAuth();
  const [showVideo, setShowVideo] = useState(false);
  const [bookmarked, setBookmarked] = useState(false);
  const [bookmarking, setBookmarking] = useState(false);

  useEffect(() => {
    async function checkBookmark() {
      if (!user || !listening) return;
      try {
        const docRef = doc(db, 'bookmarks', user.uid, 'userBookmarks', listening.id);
        const snap = await getDoc(docRef);
        setBookmarked(snap.exists());
      } catch (err) {
        console.error("Failed to check bookmark", err);
      }
    }
    checkBookmark();
  }, [user, listening]);

  const toggleBookmark = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!user || !listening) return;
    setBookmarking(true);
    try {
      const docRef = doc(db, 'bookmarks', user.uid, 'userBookmarks', listening.id);
      if (bookmarked) {
        await deleteDoc(docRef);
        setBookmarked(false);
      } else {
        await setDoc(docRef, { ...listening, bookmarkedAt: new Date() });
        setBookmarked(true);
      }
    } catch (err) {
      console.error("Bookmarking failed", err);
    } finally {
      setBookmarking(false);
    }
  };

  const extractVideoId = (url: string) => {
    const match = url.match(/(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|watch\?.+&v=))([^&?\n]+)/);
    return match ? match[1] : null;
  };

  if (!listening) {
    return (
      <div className="w-full h-64 border-2 border-dashed border-gray-300 rounded-3xl flex flex-col items-center justify-center text-gray-500">
        <p className="font-semibold text-lg">Daily Sadhana hasn't started yet</p>
        <p className="text-sm">Check back on the start date.</p>
      </div>
    );
  }

  const videoId = extractVideoId(listening.url);
  const displayDateStr = new Date(publishedDateStr + 'T00:00:00').toLocaleDateString('en-US', { day: 'numeric', month: 'long', year: 'numeric' });

  return (
    <div className="w-full max-w-2xl mx-auto rounded-[2rem] bg-[#fdfaf6] border border-orange-100 shadow-[0_8px_30px_rgb(0,0,0,0.04)] overflow-hidden transition-all duration-300">

      {/* Header Area */}
      <div className="p-6 sm:p-8 flex flex-col gap-4 relative">
        <div className="flex justify-between items-start">
          <div className="flex flex-col gap-1">
            <span className="text-orange-600 font-bold uppercase tracking-wider text-xs">
              Daily Sadhana
            </span>
            <h2 className="text-2xl sm:text-3xl font-extrabold text-gray-900 leading-tight">
              {isToday ? `Today's Listening` : `Listening for ${displayDateStr}`}
            </h2>
            <p className="text-gray-500 text-sm font-medium">
              {displayDateStr}
            </p>
          </div>

          <div className="flex flex-col gap-2 items-end">
            <span className="bg-orange-100 text-orange-800 text-xs font-bold px-3 py-1 rounded-full whitespace-nowrap">
              #{listening.number}
            </span>
            {isToday && (
              <span className={`text-xs font-bold px-3 py-1 rounded-full whitespace-nowrap ${
                alreadySubmitted ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'
              }`}>
                {alreadySubmitted ? 'Submitted' : 'Published'}
              </span>
            )}
          </div>
        </div>

        {/* Action Bar */}
        <div className="flex gap-2 items-center mt-2">
          <button 
            onClick={toggleBookmark}
            disabled={bookmarking}
            className={`p-2 rounded-full transition-colors flex items-center justify-center ${bookmarked ? 'bg-orange-100 text-orange-600' : 'bg-white text-gray-400 hover:text-orange-500 hover:bg-orange-50'} shadow-sm border border-gray-100`}
            title="Bookmark"
          >
            {bookmarking ? <Loader2 size={18} className="animate-spin" /> : <Bookmark size={18} fill={bookmarked ? "currentColor" : "none"} />}
          </button>

          <a
            href={listening.url}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-1 flex items-center gap-2 justify-center py-2 px-4 bg-white border border-gray-200 shadow-sm rounded-full text-sm font-semibold text-gray-700 hover:text-red-600 hover:border-red-200 transition-colors"
          >
            <Youtube size={18} className="text-red-500" /> Watch on YouTube
          </a>
        </div>
      </div>

      {/* Content Area */}
      <div className="px-6 sm:px-8 pb-6 sm:pb-8">
        <h3 className="text-xl font-bold text-gray-800 mb-6 border-l-4 border-orange-400 pl-4">{listening.title}</h3>

        {videoId ? (
          <div className="mt-4 rounded-xl overflow-hidden bg-black aspect-video relative group">
            {!showVideo ? (
              <div 
                className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-white/10 transition-colors"
                onClick={() => setShowVideo(true)}
              >
                <img 
                  src={`https://img.youtube.com/vi/${videoId}/hqdefault.jpg`} 
                  alt={listening.title} 
                  className="absolute inset-0 w-full h-full object-cover opacity-60"
                />
                <PlayCircle size={64} className="text-white relative z-10 drop-shadow-lg opacity-90 group-hover:scale-110 transition-transform" />
                <span className="text-white relative z-10 font-medium text-sm mt-2 drop-shadow-md bg-black/50 px-3 py-1 rounded-full">Play Embedded</span>
              </div>
            ) : (
              <iframe
                width="100%"
                height="100%"
                src={`https://www.youtube.com/embed/${videoId}?autoplay=1`}
                title={listening.title}
                frameBorder="0"
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                allowFullScreen
                className="absolute inset-0"
              ></iframe>
            )}
          </div>
        ) : (
          <div className="mt-4 p-4 bg-gray-100 rounded-xl text-center text-sm text-gray-500">
            No valid YouTube URL provided for preview.
          </div>
        )}

        {isToday && onSubmitted && (
          <SubmitPanel 
            listeningNumber={listening.number}
            publishedDateStr={publishedDateStr}
            onSubmitted={onSubmitted}
            alreadySubmitted={alreadySubmitted || false}
          />
        )}
      </div>

    </div>
  );
}

